 * Squidley V2 Core Contracts
 * ============================================================
 * Every module, every app, every integration imports from here.
 * If it isn't in contracts, it doesn't exist as a platform concept.
 *
 * Rules:
 *   - No runtime code in this file. Types and interfaces only.
 *   - No imports from anywhere except shared/types.
 *   - Changing this file is an architectural decision, not a code change.
 * ============================================================
 */

// ─── Module Identity ──────────────────────────────────────────────────────────

export type ModuleCategory = "system" | "integration" | "experience" | "persona";

export interface ModuleManifest {
  /** Unique reverse-DNS style ID. e.g. "squidley.weather" */
  id: string;
  /** Human-readable name */
  name: string;
  /** semver */
  version: string;
  /** Core SDK version this module targets */
  apiVersion: string;
  description: string;
  category: ModuleCategory;
  author?: string;
  /** Optional: path to persona.json if this is a persona module */
  personaConfig?: string;
}

// ─── Capabilities ─────────────────────────────────────────────────────────────

export type Capability =
  | "fs.read"
  | "fs.write"
  | "network.outbound"
  | "network.inbound"
  | "provider.model"
  | "shell.exec"
  | "systemctl"
  | "notifications"
  | "background.jobs"
  | "calendar.read"
  | "email.read"
  | "ui.contribute"
  | "receipts.write"
  | "receipts.read"
  | "memory.read"
  | "memory.write"
  | "tools.register"
  | "events.subscribe"
  | "events.emit";

export interface CapabilityGrant {
  capability: Capability;
  granted: boolean;
  reason?: string;
}

// ─── Module Health ────────────────────────────────────────────────────────────

export type HealthStatus =
  | "healthy"
  | "degraded"
  | "failed"
  | "disabled"
  | "blocked"
  | "misconfigured";

/**
 * Trust level — how much should the system rely on this module right now?
 *
 *   built      — code exists, not yet exercised in production
 *   verified   — passes its own health checks and probes
 *   trusted    — verified + has recent successful operations (last-known-good < 24h)
 *   degraded   — was trusted but is currently experiencing issues
 *
 * Modules self-report trust via healthCheck(). Core never overrides.
 */
export type TrustLevel = "built" | "verified" | "trusted" | "degraded";

export interface HealthReport {
  status: HealthStatus;
  message?: string;
  checks?: Record<string, boolean>;
  /** ISO timestamp of last status change */
  since?: string;
  /** Which module ID is blocking this module, if status === "blocked" */
  blockedBy?: string;
  /** When true, degraded is expected/normal (e.g. optional local server offline). Filed as INFO, never WARN/CRITICAL. */
  expectedDegraded?: boolean;
  /** Self-reported trust level. Modules that don't report default to "built". */
  trust?: TrustLevel;
  /** ISO timestamp of last successful operation (receipt-backed) */
  lastKnownGood?: string;
}

// ─── Source Attribution ──────────────────────────────────────────────────────
/**
 * Universal footer for any recommendation, finding, or assessment.
 * Every module that produces actionable output should attach this.
 *
 * source:        which module/system produced this (e.g. "archelon", "crucible", "sibyl")
 * confidence:    how sure is the source? high = verified data, medium = inference, low = guess
 * actionability: auto = system can act, suggest = human should decide, ask = needs more info
 */
export type Confidence = "high" | "medium" | "low";
export type Actionability = "auto" | "suggest" | "ask";

export interface SourceAttribution {
  source: string;
  confidence: Confidence;
  actionability: Actionability;
  /** Optional: why this confidence level? Keeps the reasoning inspectable. */
  reason?: string;
}

// ─── Module Contract ─────────────────────────────────────────────────────────
/**
 * What does this module promise, and what happens when it can't deliver?
 * Modules declare this statically. Core uses it for dependency health,
 * degraded-mode decisions, and operator reporting.
 */
export interface ModuleContract {
  /** What this module guarantees when healthy (e.g. "Routes model calls to cheapest available provider") */
  promise: string;
  /** How to verify the promise holds (e.g. "smoke test via /nous/models/:id/test") */
  proofPath: string;
  /** What happens when this module is unavailable */
  degradedBehavior: string;
  /** Which team/person owns fixing failures (e.g. "core", "jeff", "auto-recovery") */
  failureOwner: string;
}

// ─── Last Known Good ─────────────────────────────────────────────────────────
/**
 * Tracks the most recent successful operation for a component.
 * Receipt-backed — derived from receipt JSONL, not module self-report.
 */
export interface LastKnownGood {
  /** Component or module ID */
  componentId: string;
  /** ISO timestamp of last successful receipt */
  timestamp: string;
  /** What the last successful operation was */
  reason: string;
  /** How long ago in seconds */
  ageSeconds: number;
  /** Is this stale? (> 24h since last success) */
  stale: boolean;
}

// ─── Module Dependencies ──────────────────────────────────────────────────────

export interface ModuleDependencies {
  /** Module IDs that must be present and healthy for this module to load */
  required: string[];
  /** Module IDs used if available, but not required */
  optional: string[];
  /** semver constraints keyed by module ID */
  versionRequirements: Record<string, string>;
  /** Module IDs that cannot be loaded alongside this module */
  incompatibleWith?: string[];
}

// ─── Config ───────────────────────────────────────────────────────────────────

export type ConfigFieldType = "string" | "number" | "boolean" | "array" | "object";

export interface ConfigField {
  type: ConfigFieldType;
  description: string;
  required: boolean;
  default?: unknown;
  secret?: boolean;
}

export interface ModuleConfig {
  schema: Record<string, ConfigField>;
  required: string[];
  defaults: Record<string, unknown>;
  /** Names of env vars this module expects for secrets */
  secrets?: string[];
}

// ─── UI Contributions ─────────────────────────────────────────────────────────

export type UIContributionType =
  | "tab"
  | "panel"
  | "card"
  | "widget"
  | "settings"
  | "action";

export interface UIContribution {
  type: UIContributionType;
  id: string;
  label: string;
  icon?: string;
  /** Sort order in nav */
  position?: number;
  requiredCapabilities?: Capability[];
  /** Reference string — NOT a direct import. Core resolves this at boot. */
  componentRef: string;
}

// ─── Events ───────────────────────────────────────────────────────────────────

export interface EventSpec {
  subscribes: string[];
  emits: string[];
}

/** Base shape for all platform events */
export interface PlatformEvent {
  type: string;
  moduleId: string;
  timestamp: string;
  payload?: unknown;
}

// ─── Services ─────────────────────────────────────────────────────────────────

export interface ServiceContribution {
  /** e.g. "weather.current" */
  serviceId: string;
  /** Interface name from SDK */
  interfaceName: string;
  implementation: unknown;
}

// ─── Module Context ───────────────────────────────────────────────────────────
/**
 * The object passed to every module's init() hook.
 * This is the only way modules interact with core.
 * Modules must not reach outside of ctx.
 */
export interface ModuleContext {
  moduleId: string;
  config: Record<string, unknown>;
  capabilities: CapabilityGrant[];
  /** Emit an event onto the platform bus */
  emit: (event: Omit<PlatformEvent, "moduleId" | "timestamp">) => void;
  /** Subscribe to platform events */
  subscribe: (eventType: string, handler: (event: PlatformEvent) => void) => () => void;
  /** Write a receipt entry */
  receipt: (entry: ReceiptEntry) => void;
  /** Register a service for other modules to consume */
  registerService: (contribution: ServiceContribution) => void;
  /** Consume a service registered by another module */
  getService: <T>(serviceId: string) => T | null;
  /** Log with module context attached */
  log: ModuleLogger;
}

// ─── Module Lifecycle ─────────────────────────────────────────────────────────

export interface ModuleLifecycle {
  /** Called once on first install only */
  install?(): Promise<void>;
  /** Required. Called with platform context. Module sets itself up here. */
  init(ctx: ModuleContext): Promise<void>;
  /** Required. Called after all modules are init'd. Module starts work here. */
  start(): Promise<void>;
  /** Required. Called on shutdown. Must release all resources. */
  stop(): Promise<void>;
  /** Required. Returns current health. Called periodically by diagnostics. */
  healthCheck(): Promise<HealthReport>;
  /** Optional. Called if module version changed since last boot. */
  migrate?(fromVersion: string): Promise<void>;
}

// ─── Full Module Definition ───────────────────────────────────────────────────

export interface SquidleyModule extends ModuleLifecycle {
  manifest: ModuleManifest;
  dependencies: ModuleDependencies;
  config: ModuleConfig;
  capabilities: Capability[];
  events: EventSpec;
  uiContributions?: UIContribution[];
  serviceContributions?: ServiceContribution[];
  /** What this module promises and how to verify it. Optional — modules adopt incrementally. */
  contract?: ModuleContract;
}

// ─── Persona ──────────────────────────────────────────────────────────────────
/**
 * A persona is pure data. It never contains code.
 * It cannot change which modules load, which tools are available,
 * or any platform capability. It is cosmetic all the way down.
 */
export interface PersonaConfig {
  id: string;
  name: string;
  /** Displayed in UI header */
  displayName: string;
  /** The system prompt injected at the start of every conversation */
  systemPrompt: string;
  /** Short personality description shown in UI */
  description: string;
  /** Optional CSS theme overrides — colors and fonts only */
  theme?: PersonaTheme;
  /** Optional greeting shown on fresh chat */
  greeting?: string;
}

export interface PersonaTheme {
  /** CSS custom property overrides. Keys must start with "--squidley-" */
  cssVars?: Record<string, string>;
  /** Display name for the theme, shown in settings */
  label?: string;
}

// ─── Receipts ─────────────────────────────────────────────────────────────────

export type ReceiptComponentType =
  | "model-call"
  | "tool-exec"
  | "agent-run"
  | "module-event"
  | "capability-grant"
  | "capability-deny";

export type ReceiptContext = "production" | "benchmark" | "test" | "diagnostic";

export interface ReceiptEntry {
  id?: string;
  timestamp?: string;
  componentType: ReceiptComponentType;
  componentName: string;
  moduleId: string;
  /** Human-readable reason this action was taken */
  reason: string;
  model?: string;
  tokensIn?: number;
  tokensOut?: number;
  estimatedCostUsd?: number;
  durationMs?: number;
  status: "success" | "failure" | "warn";
  /** Was the result shown to the user */
  surfacedToUser: boolean;
  /**
   * Execution context — distinguishes production calls from benchmark/test/diagnostic.
   * Defaults to "production" if unset. Benchmark and test failures must not be
   * escalated as production incidents.
   */
  context?: ReceiptContext | undefined;
  meta?: Record<string, unknown>;
}

// ─── Change Summary ──────────────────────────────────────────────────────────
/**
 * "What changed since X?" — the nervous system query.
 * Receipt-backed. Feeds Sibyl, syscheck, Colloquium, /platform/trust.
 */
export interface ChangeSummary {
  /** ISO timestamp of the "since" boundary */
  since: string;
  /** ISO timestamp when this summary was generated */
  generatedAt: string;
  /** Total receipts scanned */
  receiptsScanned: number;

  /** Counts by category */
  counts: {
    modelCalls: number;
    toolExecs: number;
    agentRuns: number;
    failures: number;
    moduleEvents: number;
  };

  /** Failures grouped by component — the repeat-offender view */
  failuresByComponent: Array<{
    component: string;
    count: number;
    lastFailure: string;
    lastReason: string;
    /** true if 3+ failures from same component = repeat offender */
    repeatOffender: boolean;
  }>;

  /** Model calls grouped by provider — spend since last check */
  spendByProvider: Array<{
    provider: string;
    calls: number;
    costUsd: number;
  }>;

  /** Significant events — things a human should know about */
  highlights: string[];
}

// ─── Error Envelope ──────────────────────────────────────────────────────────
/**
 * Standard error response shape. Every error from any endpoint follows this.
 * Monitoring keys on `ok === false`. Correlation via `requestId`.
 */
export interface ErrorEnvelope {
  ok: false;
  error: string;
  /** Machine-readable error code (e.g. "MODULE_UNAVAILABLE", "VALIDATION_FAILED") */
  code?: string;
  /** Additional context for debugging */
  detail?: string;
  /** Correlation ID from X-Request-Id header */
  requestId?: string;
}

// ─── Runtime Mode ─────────────────────────────────────────────────────────────

export type RuntimeMode =
  | "local-only"      // No cloud providers. Local models only.
  | "cloud-authorized" // Cloud providers allowed.
  | "forge"           // Full lab stack. All capabilities.
  | "minimal";        // Pi/phone mode. Core + essentials only.

// ─── Platform Events (well-known types) ───────────────────────────────────────

export const PLATFORM_EVENTS = {
  MODULE_LOADED: "module.loaded",
  MODULE_READY: "module.ready",
  MODULE_DEGRADED: "module.degraded",
  MODULE_FAILED: "module.failed",
  MODULE_STOPPED: "module.stopped",
  PLATFORM_READY: "platform.ready",
  PLATFORM_SHUTDOWN: "platform.shutdown",
  CAPABILITY_GRANTED: "capability.granted",
  CAPABILITY_DENIED: "capability.denied",
} as const;

// ─── Logger ───────────────────────────────────────────────────────────────────

export interface ModuleLogger {
  info: (msg: string, meta?: Record<string, unknown>) => void;
  warn: (msg: string, meta?: Record<string, unknown>) => void;
  error: (msg: string, meta?: Record<string, unknown>) => void;
  debug: (msg: string, meta?: Record<string, unknown>) => void;
}
